import React, { useEffect, useMemo, useState } from 'react';
import { Asset } from '../services/api';
import useResizableColumns from './useResizableColumns';

type ColumnField = 'product_type' | 'product' | 'assigned_user' | 'department' | 'asset_state' | 'location';
type SortDirection = 'asc' | 'desc';

const defaultColumnWidths: Record<ColumnField, number> = {
  product_type: 190,
  product: 220,
  assigned_user: 190,
  department: 180,
  asset_state: 180,
  location: 180,
};

const columns = [
  { field: 'product_type' as ColumnField, label: 'Product Type' },
  { field: 'product' as ColumnField, label: 'Product' },
  { field: 'assigned_user' as ColumnField, label: 'User' },
  { field: 'department' as ColumnField, label: 'Department' },
  { field: 'asset_state' as ColumnField, label: 'Asset State' },
  { field: 'location' as ColumnField, label: 'Location' },
];

interface AssetTableProps {
  assets: Asset[];
  loading?: boolean;
  error?: string | null;
  selectedRows: string[];
  onSelectedRowsChange: (selected: string[]) => void;
  onView: (asset: Asset) => void;
  onEdit: (asset: Asset) => void;
}

const AssetTable: React.FC<AssetTableProps> = ({
  assets,
  loading,
  error,
  selectedRows,
  onSelectedRowsChange,
  onView,
  onEdit,
}) => {
  const [pageSize, setPageSize] = useState<number>(10);
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [sortField, setSortField] = useState<ColumnField>('product_type');
  const [sortDirection, setSortDirection] = useState<SortDirection>('asc');
  const { getColumnStyle, renderResizeHandle } = useResizableColumns<ColumnField>(defaultColumnWidths);

  const sortedAssets = useMemo(() => {
    return [...assets].sort((a, b) => {
      const aValue = (a[sortField] || '').toString().toLowerCase();
      const bValue = (b[sortField] || '').toString().toLowerCase();
      const result = aValue.localeCompare(bValue, undefined, { numeric: true, sensitivity: 'base' });
      return sortDirection === 'asc' ? result : -result;
    });
  }, [assets, sortDirection, sortField]);

  const totalPages = Math.max(1, Math.ceil(sortedAssets.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const pageRows = useMemo(() => sortedAssets.slice(startIndex, startIndex + pageSize), [sortedAssets, startIndex, pageSize]);
  const allSelected = pageRows.length > 0 && pageRows.every((row) => selectedRows.includes(row.id));

  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages);
    }
  }, [currentPage, totalPages]);

  const toggleRow = (id: string) => {
    if (selectedRows.includes(id)) {
      onSelectedRowsChange(selectedRows.filter((value) => value !== id));
    } else {
      onSelectedRowsChange([...selectedRows, id]);
    }
  };

  const toggleAll = () => {
    if (allSelected) {
      onSelectedRowsChange(selectedRows.filter((id) => !pageRows.some((row) => row.id === id)));
    } else {
      const next = Array.from(new Set([...selectedRows, ...pageRows.map((row) => row.id)]));
      onSelectedRowsChange(next);
    }
  };

  const handleSort = (field: ColumnField) => {
    if (sortField === field) {
      setSortDirection((currentDirection) => (currentDirection === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortField(field);
      setSortDirection('asc');
    }
    setCurrentPage(1);
  };

  const renderSortIcon = (field: ColumnField) => (
    <span className={`ml-2 text-[10px] leading-none ${sortField === field ? 'text-blue-600' : 'text-slate-400'}`} aria-hidden="true">
      {sortField === field && sortDirection === 'desc' ? '\u25BC' : '\u25B2'}
    </span>
  );

  const renderColumnHeader = (field: ColumnField, label: string) => (
    <th
      className="relative px-4 py-4 text-left font-semibold uppercase tracking-[0.16em]"
      style={getColumnStyle(field)}
    >
      <button
        type="button"
        onClick={() => handleSort(field)}
        className="flex w-full items-center justify-between gap-2 text-left"
        aria-label={`Sort by ${label}`}
      >
        <span className="truncate">{label}</span>
        {renderSortIcon(field)}
      </button>
      {renderResizeHandle(field)}
    </th>
  );

  return (
    <div className="overflow-hidden rounded-lg border border-slate-200 bg-white shadow-sm">
      <div className="overflow-x-auto">
        <table className="w-full min-w-[1200px] table-fixed divide-y divide-slate-200 text-sm">
          <thead className="bg-slate-50 text-slate-500">
            <tr>
              <th className="w-14 px-4 py-4 text-left">
                <input
                  type="checkbox"
                  checked={allSelected}
                  onChange={toggleAll}
                  className="h-4 w-4 rounded border-slate-300 text-blue-600"
                />
              </th>
              {columns.map((column) => renderColumnHeader(column.field, column.label))}
              <th className="w-48 px-4 py-4 text-left font-semibold uppercase tracking-[0.16em]">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200 bg-white">
            {loading && (
              <tr>
                <td colSpan={8} className="px-6 py-12 text-center text-sm text-slate-500">
                  Loading assets...
                </td>
              </tr>
            )}
            {!loading && error && (
              <tr>
                <td colSpan={8} className="px-6 py-12 text-center text-sm text-red-600">
                  {error}
                </td>
              </tr>
            )}
            {!loading && !error && pageRows.map((row) => (
              <tr key={row.id} className="hover:bg-slate-50">
                <td className="px-4 py-4 text-left">
                  <input
                    type="checkbox"
                    checked={selectedRows.includes(row.id)}
                    onChange={() => toggleRow(row.id)}
                    className="h-4 w-4 rounded border-slate-300 text-blue-600"
                  />
                </td>
                <td className="px-4 py-4 text-slate-900" style={getColumnStyle('product_type')}>{row.product_type || ''}</td>
                <td className="px-4 py-4 text-slate-900" style={getColumnStyle('product')}>{row.product || row.name}</td>
                <td className="px-4 py-4 text-slate-900" style={getColumnStyle('assigned_user')}>{row.assigned_user || ''}</td>
                <td className="px-4 py-4 text-slate-900" style={getColumnStyle('department')}>{row.department || ''}</td>
                <td className="px-4 py-4 text-slate-900" style={getColumnStyle('asset_state')}>{row.asset_state || ''}</td>
                <td className="px-4 py-4 text-slate-900" style={getColumnStyle('location')}>{row.location || ''}</td>
                <td className="px-4 py-4">
                  <div className="flex flex-wrap gap-2">
                    <button
                      type="button"
                      onClick={() => onView(row)}
                      className="inline-flex items-center gap-1.5 rounded-md border border-slate-300 bg-white px-3 py-1 text-sm text-slate-700 transition hover:bg-slate-50"
                    >
                      <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                        <path d="M2 8S4.2 4.5 8 4.5S14 8 14 8S11.8 11.5 8 11.5S2 8 2 8Z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" />
                        <path d="M8 9.5A1.5 1.5 0 1 0 8 6.5A1.5 1.5 0 0 0 8 9.5Z" fill="currentColor" />
                      </svg>
                      View
                    </button>
                    <button
                      type="button"
                      onClick={() => onEdit(row)}
                      className="inline-flex items-center gap-1.5 rounded-md border border-slate-300 bg-white px-3 py-1 text-sm text-slate-700 transition hover:bg-slate-50"
                    >
                      <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                        <path d="M3 11.5V13H4.5L11.5 6L10 4.5L3 11.5Z" fill="currentColor" />
                        <path d="M10.8 3.7L12.3 5.2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
                      </svg>
                      Edit
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {!loading && !error && pageRows.length === 0 && (
              <tr>
                <td colSpan={8} className="px-6 py-12 text-center text-sm text-slate-500">
                  No assets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="flex flex-col gap-4 border-t border-slate-200 px-5 py-4 text-sm text-slate-600 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2">
          <span>Page Size:</span>
          <select
            value={pageSize}
            onChange={(event) => {
              setPageSize(Number(event.target.value));
              setCurrentPage(1);
            }}
            className="rounded-md border border-slate-300 bg-white px-3 py-1 text-sm text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
          </select>
        </div>

        <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
          <span>
            {sortedAssets.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(startIndex + pageSize, sortedAssets.length)} of ${sortedAssets.length}`}
          </span>
          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={() => setCurrentPage((page) => Math.max(1, page - 1))}
              disabled={currentPage === 1}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              &#8592;
            </button>
            <span className="text-sm text-slate-600">Page {currentPage} of {totalPages}</span>
            <button
              type="button"
              onClick={() => setCurrentPage((page) => Math.min(totalPages, page + 1))}
              disabled={currentPage === totalPages}
              className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              &#8594;
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssetTable;
